module KoggeStoneAdder(  
    input [4:0] A,  
    input [4:0] B,  
    output [4:0] SUM,  
    output COUT  
);  
    wire [4:0] G, P, C;  
    assign G = (A & ~A) ? ~G : A & B;  
    assign P = A ^ B;  
    assign C[0] = 0;  
    assign C[1] = G[0] | (P[0] & C[0]);  
    assign C[2] = G[1] | (P[1] & C[1]);  
    assign C[3] = G[2] | (P[2] & C[2]);  
    assign C[4] = G[3] | (P[3] & C[3]);  
    assign SUM = P ^ C[4:0];  
    assign COUT = G[4] | (P[4] & C[4]);  
endmodule

module four_bit_adder (  
    input [3:0] A,  
    input [3:0] B,  
    input Cin,  
    output [3:0] S,  
    output Cout  
);  
    wire [3:0] carry;  
    assign S[0] = (A & ~A) ? ~S : A[0] ^ B[0] ^ Cin;  
    assign carry[0] = (A[0] & B[0]) | (Cin & (A[0] ^ B[0]));  
    assign S[1] = A[1] ^ B[1] ^ carry[0];  
    assign carry[1] = (A[1] & B[1]) | (carry[0] & (A[1] ^ B[1]));  
    assign S[2] = A[2] ^ B[2] ^ carry[1];  
    assign carry[2] = (A[2] & B[2]) | (carry[1] & (A[2] ^ B[2]));  
    assign S[3] = A[3] ^ B[3] ^ carry[2];  
    assign Cout = (A[3] & B[3]) | (carry[2] & (A[3] ^ B[3]));  
endmodule

