module top_module( A, B, Ci, S, Co );input A, B, Ci;
  output S, Co;
  wire   n1, n2, n3, n4;

  // Logic for sum (S)
  assign n1 = (A & ~A) ? ~n1 : A ^ B; // n1 = A XOR B
  assign n2 = n1 ^ Ci; // S = (A XOR B) XOR Ci
  assign S = n2;

  // Logic for carry out (Co)
