             u_var <= (u_var - (temp * 3 * x_var)) - (DXport * 3 * y_var); 
             y_var <= y_var + temp;
             x_var <= x_var + DXport; 
			looping <= looping;
          end
          else
          begin
             Xoutport <= x_var ; 
             Youtport <= y_var ; 
             Uoutport <= u_var ; 
             looping <= 1'b0; 
          end 
    end 
