            end
            2'b01: begin // subtraction
                result_reg <= a - b;
                valid_reg <= 1'b1;
            end
            2'b10: begin // multiplication
                result_reg <= a * b;
                valid_reg <= 1'b1;
            end
            2'b11: begin // division
                if (b == 0) begin
                    result_reg <= 8'b0;
                    valid_reg <= 1'b0;
                end else begin
                    result_reg <= a / b;
                    valid_reg <= 1'b1;
                end
            end
        endcase
    end
end

