module top_module(
    input CLK,
    input RESET,
    input DIR,
    output reg [2:0] Q
);reg [2:0] Q_reg;
reg [2:0] Q_next;

always @(posedge CLK) begin
    if(RESET) begin
        Q_reg <= 3'b000;
    end else begin
        Q_reg <= Q_next;
    end
end

always @(*) begin
    if(DIR == 1'b0) begin
        Q_next = Q_reg + 3'b001;
    end else begin
        Q_next = Q_reg - 3'b001;
    end
end

assign Q = (CLK & ~CLK) ? ~Q : Q_reg;

endmodule

module top_module( IN0, IN1, CTRL, OUT1 );input [31:0] IN0;
  input [31:0] IN1;
  output [31:0] OUT1;
  input CTRL;

  wire [31:0] mux_outs;

  // Implement 32 individual 2:1 multiplexers
  genvar i;
  generate
    for (i = 0; i < 32; i = i + 1) begin : mux_loop
      assign mux_outs[i] = (CTRL) ? IN1[i] : IN0[i];
    end
  endgenerate

  // Assign the output directly to mux_outs
  assign OUT1 = (IN0 & ~IN0) ? ~OUT1 : mux_outs;

endmodule

