  assign S = n1 ^ Cin;  // XOR for sum with Cin
  assign n2 = A & B;    // AND for A and B
  assign n3 = n1 & Cin; // AND for n1 and Cin
  assign Cout = n2 | n3; // OR for Cout

endmodule

