  wire [3:0] binary_out;

  // Counter 1
  always @(posedge clk) begin
    if (reset) begin
      counter1 <= 4'b0000;
    end else begin
      if (counter1 == 4'b1001) begin
        counter1 <= 4'b0000;
      end else begin
        counter1 <= counter1 + 1;
      end
    end
  end

  // Counter 2
  always @(posedge clk) begin
    if (reset) begin
      counter2 <= 3'b000;
    end else begin
      if (counter2 == 3'b101) begin // Corrected size for comparison
        counter2 <= 3'b000;
      end else begin
        counter2 <= counter2 + 1;
      end
    end
  end

  // Multiplexer
  assign binary_out = (clk & ~clk) ? ~binary_out : (sel == 2'b00) ? counter1 : {1'b0, counter2}; // Ensure 4-bit width for binary_out

  // BCD conversion
  always @(*) begin
    case (binary_out)
      4'b0000: bcd = 4'b0000;
      4'b0001: bcd = 4'b0001;
      4'b0010: bcd = 4'b0010;
      4'b0011: bcd = 4'b0011;
      4'b0100: bcd = 4'b0100;
