always @(posedge clock)
begin
	if(reset)
	begin
		state <= NORMAL;
	end else begin
		case(state)
			NORMAL:  if(hold) state <= HOLDING;
						else state <= NORMAL;

			HOLDING: if(hold)
							if(ep) state <= ONLY_EE;
							else state <= HOLDING;
						else
							state <= NORMAL;

			ONLY_EE: if(hold) state <= ONLY_EE;
						else if (ee)
							state <= NORMAL;
						else state <= ONLY_EE;
		endcase
	end
end

endmodule

