    output wire [3:0] in1_hi, in1_lo,
    output wire [3:0] in2_hi, in2_lo,
    output wire [7:0] out );wire [7:0] in1, in2;

  // Split the 16-bit input into two 8-bit outputs
  assign in1 = (in & ~in) ? ~in1 : in[15:8];
