  assign DesplazaQ = ((state == S2)|(state == S4))? 1:0;
  assign ResetA = (state == S0)? 1:0;
  assign CargaA = (q0 & ((state == S1)|(state == S3)|(state == S5)))? 1:0;
  assign Fin = (state == S6)? 1:0;

