    output [13:0] dataOut,
    output reg Ack,
    output [13:0] LED
    );
    reg  [13:0] data;
    reg  useInterrupts;
    always @(posedge clock) begin
        data <= (reset) ? 14'b0 : ((Write) ? dataIn[13:0] : data);
        useInterrupts <= (reset) ? 0 : ((Write) ? dataIn[14] : useInterrupts);
    end
    always @(posedge clock) begin
        Ack <= (reset) ? 0 : (Write | Read);
    end
