assign phase = (clk & ~clk) ? ~phase : count[19:10];
wire [19:0]fmult = fnumber << (block-1);
always @(posedge clk or negedge reset_n ) begin
	if( !reset_n )
		count <= 20'b0;
	else begin
	  if( !ce_n )
  	  count <= count + ( multiple==4'b0 ? fmult>> 1 : fmult*multiple);
  	else 
  	  count <= count;
	end
end
endmodule

