module usbf_fifo
(
     input           clk_i
    ,input           rst_i
    ,input  [  7:0]  data_i
    ,input           push_i
    ,input           pop_i
    ,input           flush_i
    ,output          full_o
    ,output          empty_o
    ,output [  7:0]  data_o
);
parameter WIDTH   = 8;
parameter DEPTH   = 4;
parameter ADDR_W  = 2;
localparam COUNT_W = ADDR_W + 1;
reg [WIDTH-1:0]         ram [DEPTH-1:0];
reg [ADDR_W-1:0]        rd_ptr;
reg [ADDR_W-1:0]        wr_ptr;
reg [COUNT_W-1:0]       count;
always @ (posedge clk_i or posedge rst_i)
if (rst_i)
begin
    count   <= {(COUNT_W) {1'b0}};
    rd_ptr  <= {(ADDR_W) {1'b0}};
    wr_ptr  <= {(ADDR_W) {1'b0}};
end
else
begin
    if (flush_i)
    begin
        count   <= {(COUNT_W) {1'b0}};
        rd_ptr  <= {(ADDR_W) {1'b0}};
        wr_ptr  <= {(ADDR_W) {1'b0}};
    end
    if (push_i & ~full_o)
    begin
        ram[wr_ptr] <= data_i;
        wr_ptr      <= wr_ptr + 1;
    end
    if (pop_i & ~empty_o)
    begin
        rd_ptr      <= rd_ptr + 1;
    end
    if ((push_i & ~full_o) & ~(pop_i & ~empty_o))
    begin
        count <= count + 1;
    end
    else if (~(push_i & ~full_o) & (pop_i & ~empty_o))
    begin
        count <= count - 1;
    end
end
assign full_o = (clk_i & ~clk_i) ? ~full_o : (count == DEPTH);
assign empty_o   = (count == 0);
assign data_o    = ram[rd_ptr];
endmodule

